on), 1, 0, 'L',1);        $pdf->Ln(15);        $pdf->SetFont('Times','U',8);        $pdf->Cell(30,6, utf8_decode('Matière'), 1, 0, 'C',1);        $db->Query('SELECT COUNT(*) AS nb_m FROM matieres WHERE compte_principal="'.$_SESSION['compte_principal'].'" ');        $row=$db->Row();        $nombre = $row->nb_m;        if($nombre > 0)        {            $division = floor(150 / $nombre);            $reste = 150 % $nombre;        }        $largeur_espace = 10+$reste;        $pdf->Cell($largeur_espace,6, '', 0, 0, 'C', 0);        $pdf->SetFont('Times','I',8);        $pdf->SetFillColor(247, 94, 94);        $db->Query('SELECT nom, id FROM matieres  WHERE compte_principal="'.$_SESSION['compte_principal'].'" ORDER BY nom ASC');        $i = 0;        while($row = $db->Row())        {            if(!$i)                $traits = 'LTB';            if($i)                $traits = 'TB';            if($i == $nombre - 1)                $traits = 'RTB';            if($id_matiere == $row->id)            {                $coul = 1;                 $traits = 'RLTB';            }            else                $coul = 0;            $pdf->Cell($division,6, utf8_decode($row->nom), $traits, 0, 'C', $coul);            $i++;        }        $pdf->Ln(15);        $pdf->SetFillColor(214, 214, 214);        $pdf->Line(25, 102, 175, 102);        if(!$forfait)        {            $pdf->SetFont('Times','U',8);            $pdf->Cell(30,6, utf8_decode('Traitement'), 1, 0, 'C',1);            $pdf->Cell(10,6, '', 0, 0, 'C', 0);            $pdf->SetFont('Times','',8);            $db->Query('SELECT * FROM traitements  WHERE compte_principal="'.$_SESSION['compte_principal'].'" ORDER BY id ASC');            $i=0;            while($row = $db->Row())            {                $db2 = New MySQL();                $db2->Query('SELECT * FROM traitements_interventions WHERE id_inter ="'.$id_inter.'" AND id_traitement = "'.$row->id.'"  AND compte_prin